import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

const filePath = path.join(process.cwd(), "data", "users.json");

const readUsersFile = () => {
  try {
    if (!fs.existsSync(filePath)) {
      const defaultUsers = [
        { id: "EMP-101", name: "Ramesh Pawar", role: "Service Advisor", email: "ramesh@livebay.com" },
        { id: "EMP-102", name: "Amit Patel", role: "Technician", email: "amit@livebay.com" },
        { id: "EMP-103", name: "Suresh Kumar", role: "Technician", email: "suresh@livebay.com" }
      ];
      const dirPath = path.dirname(filePath);
      if (!fs.existsSync(dirPath)) fs.mkdirSync(dirPath, { recursive: true });
      fs.writeFileSync(filePath, JSON.stringify(defaultUsers, null, 2), "utf-8");
      return defaultUsers;
    }
    return JSON.parse(fs.readFileSync(filePath, "utf-8"));
  } catch (error) {
    return [];
  }
};

const writeUsersFile = (data: any) => {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
};

export async function GET() {
  return NextResponse.json(readUsersFile());
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { name, role, email } = body;

    if (!name || !role || !email) {
      return NextResponse.json({ error: "Missing required profile parameters." }, { status: 400 });
    }

    const currentUsers = readUsersFile();
    const nextId = `EMP-${currentUsers.length + 101}`;

    const newEmployee = { id: nextId, name, role, email };
    currentUsers.push(newEmployee);
    writeUsersFile(currentUsers);

    return NextResponse.json({ success: true, data: newEmployee }, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: "Internal Server Error saving employee." }, { status: 500 });
  }
}